#!/usr/bin/env python3
"""
Puzzle solver using edge-matching with greedy search + backtracking.
"""

import os
import sys
import json
import numpy as np
from PIL import Image
import copy

INPUT_DIR = "/tmp_workspace/input/"
OUTPUT_DIR = "/tmp_workspace/results/"
os.makedirs(OUTPUT_DIR, exist_ok=True)

PIECE_SIZE = 150
GRID_SIZE = 4
ROTATIONS = [0, 90, 180, 270]

# Load all pieces
pieces = {}
for i in range(1, 25):
    fname = f"piece_{i:02d}.png"
    path = os.path.join(INPUT_DIR, fname)
    img = Image.open(path).convert("RGB")
    pieces[fname] = np.array(img, dtype=np.float32)

fnames = sorted(pieces.keys())
print(f"Loaded {len(pieces)} pieces, size: {pieces[fnames[0]].shape}")

def rotate_arr(arr, cw_degrees):
    """Rotate array by CW degrees (undo rotation by rotating back)."""
    k = (360 - cw_degrees) // 90 % 4  # CCW rotations to undo CW
    return np.rot90(arr, k=k)

def get_edges(arr, cw_rotation=0):
    """Get edges after undoing the rotation."""
    a = rotate_arr(arr, cw_rotation)
    return {
        'top': a[0, :, :],
        'right': a[:, -1, :],
        'bottom': a[-1, :, :],
        'left': a[:, 0, :]
    }

# Precompute edges for all pieces and rotations
print("Precomputing edges...")
edges = {}
for fname in fnames:
    edges[fname] = {}
    for rot in ROTATIONS:
        edges[fname][rot] = get_edges(pieces[fname], rot)

def edge_score(e1, e2):
    """MAE between two edges - lower means better match."""
    return np.mean(np.abs(e1 - e2))

# Precompute all pairwise scores
print("Precomputing pairwise scores...")
# h_score[f1][r1][f2][r2] = score for f1-right vs f2-left
h_scores = {}
v_scores = {}

for f1 in fnames:
    h_scores[f1] = {}
    v_scores[f1] = {}
    for r1 in ROTATIONS:
        h_scores[f1][r1] = {}
        v_scores[f1][r1] = {}
        for f2 in fnames:
            if f1 == f2:
                continue
            h_scores[f1][r1][f2] = {}
            v_scores[f1][r1][f2] = {}
            for r2 in ROTATIONS:
                h_scores[f1][r1][f2][r2] = edge_score(
                    edges[f1][r1]['right'], edges[f2][r2]['left']
                )
                v_scores[f1][r1][f2][r2] = edge_score(
                    edges[f1][r1]['bottom'], edges[f2][r2]['top']
                )

print("Done precomputing")

# Greedy grid assembly
# State: grid[row][col] = (fname, rotation) or None
# Fill left-to-right, top-to-bottom

def greedy_fill(starting_piece_rot=None):
    """
    Try to fill 4x4 grid greedily.
    Returns (grid, total_score) where grid[r][c] = (fname, rot)
    """
    grid = [[None]*4 for _ in range(4)]
    used = set()

    def score_candidate(row, col, fname, rot):
        """Score a candidate for position (row, col)."""
        s = 0
        count = 0
        # Check left neighbor
        if col > 0 and grid[row][col-1] is not None:
            lf, lr = grid[row][col-1]
            s += h_scores[lf][lr][fname][rot]
            count += 1
        # Check top neighbor
        if row > 0 and grid[row-1][col] is not None:
            tf, tr = grid[row-1][col]
            s += v_scores[tf][tr][fname][rot]
            count += 1
        if count == 0:
            return 0
        return s / count

    def best_candidate(row, col):
        """Find best (fname, rot) for position (row, col)."""
        best_score = float('inf')
        best = None
        for fname in fnames:
            if fname in used:
                continue
            for rot in ROTATIONS:
                s = score_candidate(row, col, fname, rot)
                if s < best_score:
                    best_score = s
                    best = (fname, rot)
        return best, best_score

    # If starting piece is given, place it at (0,0)
    if starting_piece_rot is not None:
        grid[0][0] = starting_piece_rot
        used.add(starting_piece_rot[0])
        start_pos = 1
    else:
        start_pos = 0

    total_score = 0
    pos = start_pos

    for pos in range(start_pos, 16):
        row = pos // 4
        col = pos % 4
        best, bs = best_candidate(row, col)
        if best is None:
            return None, float('inf')
        grid[row][col] = best
        used.add(best[0])
        total_score += bs

    return grid, total_score

# Try multiple starting pieces and pick the best arrangement
print("Running greedy assembly...")

best_grid = None
best_score = float('inf')

# First, try without fixing starting piece
grid, score = greedy_fill()
print(f"Greedy (no fix): score={score:.2f}")
if score < best_score:
    best_score = score
    best_grid = grid

# Try fixing each piece as starting corner
for fname in fnames[:8]:  # Try first few
    for rot in ROTATIONS:
        g, s = greedy_fill((fname, rot))
        if s < best_score:
            best_score = s
            best_grid = g

print(f"Best greedy score: {best_score:.2f}")

def grid_total_score(grid):
    """Compute total edge compatibility score for a complete grid."""
    total = 0
    count = 0
    for row in range(4):
        for col in range(4):
            if grid[row][col] is None:
                continue
            f, r = grid[row][col]
            if col < 3 and grid[row][col+1] is not None:
                f2, r2 = grid[row][col+1]
                total += h_scores[f][r][f2][r2]
                count += 1
            if row < 3 and grid[row+1][col] is not None:
                f2, r2 = grid[row+1][col]
                total += v_scores[f][r][f2][r2]
                count += 1
    return total / count if count > 0 else float('inf')

final_score = grid_total_score(best_grid)
print(f"Final grid score: {final_score:.2f}")

print("\nGrid:")
for row in range(4):
    for col in range(4):
        if best_grid[row][col]:
            f, r = best_grid[row][col]
            print(f"  [{row},{col}]: {f} rot={r}")
        else:
            print(f"  [{row},{col}]: None")

# Identify distractors
used_pieces = set()
for row in range(4):
    for col in range(4):
        if best_grid[row][col]:
            used_pieces.add(best_grid[row][col][0])

distractors = [f for f in fnames if f not in used_pieces]
print(f"\nDistractors ({len(distractors)}): {distractors}")

# Build transforms dict (only non-zero rotations)
transforms = {}
for row in range(4):
    for col in range(4):
        if best_grid[row][col]:
            fname, rot = best_grid[row][col]
            if rot != 0:
                transforms[fname] = f"rotate_{rot}"

print(f"Transforms: {transforms}")

# Assemble the image
print("\nAssembling image...")
result = Image.new("RGB", (600, 600))

for row in range(4):
    for col in range(4):
        if best_grid[row][col]:
            fname, rot = best_grid[row][col]
            arr = pieces[fname]
            # Undo the rotation (rotate back)
            corrected_arr = rotate_arr(arr, rot).astype(np.uint8)
            piece_img = Image.fromarray(corrected_arr)
            result.paste(piece_img, (col * PIECE_SIZE, row * PIECE_SIZE))

output_path = os.path.join(OUTPUT_DIR, "assembled.png")
result.save(output_path)
print(f"Saved to {output_path}")

# Save result.json
grid_names = [[None]*4 for _ in range(4)]
for row in range(4):
    for col in range(4):
        if best_grid[row][col]:
            grid_names[row][col] = best_grid[row][col][0]

result_json = {
    "grid": grid_names,
    "transforms": transforms,
    "distractors": distractors,
    "description": "待视觉识别后填写"
}

json_path = os.path.join(OUTPUT_DIR, "result.json")
with open(json_path, 'w', encoding='utf-8') as f:
    json.dump(result_json, f, ensure_ascii=False, indent=2)
print(f"Saved result.json to {json_path}")
print("Done!")

