    used = set()

    def cand_score(row, col, f, r):
        s, n = 0.0, 0
        if col>0 and grid[row][col-1]:
            lf,lr = grid[row][col-1]
            s += h_sc[lf][lr][f][r]; n+=1
        if row>0 and grid[row-1][col]:
            tf,tr = grid[row-1][col]
            s += v_sc[tf][tr][f][r]; n+=1
        return s/n if n>0 else 0.0

    def best_for(row, col):
        best_s, best_c = float('inf'), None
        for f in fnames:
            if f in used: continue
            for r in ROTATIONS:
                s = cand_score(row, col, f, r)
                if s < best_s:
                    best_s, best_c = s, (f,r)
        return best_c, best_s

    start_pos = 0
    if start:
        grid[0][0] = start
        used.add(start[0])
        start_pos = 1

    total = 0.0
    for pos in range(start_pos, 16):
        r,c = pos//4, pos%4
        best, bs = best_for(r,c)
        if not best: return None, float('inf')
        grid[r][c] = best
        used.add(best[0])
        total += bs
    return grid, total

