                f2,r2 = grid[r][c+1]
                t += h_sc[f][rot][f2][r2]; n+=1
            if r<3 and grid[r+1][c]:
                f2,r2 = grid[r+1][c]
                t += v_sc[f][rot][f2][r2]; n+=1
    return t/n if n>0 else float('inf')

final_ts = total_score(best_grid)
print(f"Final total score: {final_ts:.3f}", flush=True)

print("\nGrid layout:", flush=True)
for r in range(4):
    row_str = []
    for c in range(4):
        if best_grid[r][c]:
            f,rot = best_grid[r][c]
            row_str.append(f"{f}(r{rot})")
    print(" | ".join(row_str), flush=True)

# Assemble
print("\nAssembling...", flush=True)
result = Image.new("RGB", (600,600))
for r in range(4):
    for c in range(4):
        if best_grid[r][c]:
            f, rot = best_grid[r][c]
            arr = rotate_arr(pieces[f], rot).astype(np.uint8)
            result.paste(Image.fromarray(arr), (c*150, r*150))

result.save(OUTPUT_DIR + "assembled.png")
print("Saved assembled.png", flush=True)

# Build outputs
used_pieces = {best_grid[r][c][0] for r in range(4) for c in range(4) if best_grid[r][c]}
distractors = sorted([f for f in fnames if f not in used_pieces])
transforms = {}
for r in range(4):
    for c in range(4):
        if best_grid[r][c]:
            f,rot = best_grid[r][c]
            if rot != 0:
                transforms[f] = f"rotate_{rot}"

grid_names = [[best_grid[r][c][0] if best_grid[r][c] else None for c in range(4)] for r in range(4)]

result_data = {
    "grid": grid_names,
    "transforms": transforms,
    "distractors": distractors,
    "description": "待视觉识别"
}
with open(OUTPUT_DIR+"result.json","w",encoding="utf-8") as fp:
    json.dump(result_data, fp, ensure_ascii=False, indent=2)
print("Saved result.json", flush=True)
print("DONE", flush=True)
