ROTATIONS = [0, 90, 180, 270]

# Load all pieces
pieces = {}
for i in range(1, 25):
    fname = f"piece_{i:02d}.png"
    pieces[fname] = np.array(Image.open(INPUT_DIR + fname).convert("RGB"), dtype=np.float32)

fnames = sorted(pieces.keys())
print(f"Loaded {len(pieces)} pieces", flush=True)

def rotate_arr(arr, cw_deg):
    k = (360 - cw_deg) // 90 % 4
    return np.rot90(arr, k=k)

def get_edges(arr, cw_rot=0):
    a = rotate_arr(arr, cw_rot)
    return {'top': a[0,:,:], 'right': a[:,-1,:], 'bottom': a[-1,:,:], 'left': a[:,0,:]}

# Precompute edges
edges = {f: {r: get_edges(pieces[f], r) for r in ROTATIONS} for f in fnames}
print("Edges computed", flush=True)

def escore(e1, e2):
    return float(np.mean(np.abs(e1-e2)))

# Precompute scores
print("Computing scores...", flush=True)
h_sc = {}
v_sc = {}
for f1 in fnames:
    h_sc[f1] = {}
    v_sc[f1] = {}
    for r1 in ROTATIONS:
        h_sc[f1][r1] = {}
        v_sc[f1][r1] = {}
        for f2 in fnames:
            if f1==f2: continue
            h_sc[f1][r1][f2] = {}
            v_sc[f1][r1][f2] = {}
            for r2 in ROTATIONS:
                h_sc[f1][r1][f2][r2] = escore(edges[f1][r1]['right'], edges[f2][r2]['left'])
                v_sc[f1][r1][f2][r2] = escore(edges[f1][r1]['bottom'], edges[f2][r2]['top'])
print("Scores done", flush=True)

# Greedy fill
def greedy_fill(start=None):
    grid = [[None]*4 for _ in range(4)]
    used = set()

    def cand_score(row, col, f, r):
        s, n = 0.0, 0
        if col>0 and grid[row][col-1]:
            lf,lr = grid[row][col-1]
            s += h_sc[lf][lr][f][r]; n+=1
        if row>0 and grid[row-1][col]:
            tf,tr = grid[row-1][col]
            s += v_sc[tf][tr][f][r]; n+=1
        return s/n if n>0 else 0.0

    def best_for(row, col):
        best_s, best_c = float('inf'), None
        for f in fnames:
            if f in used: continue
            for r in ROTATIONS:
                s = cand_score(row, col, f, r)
                if s < best_s:
                    best_s, best_c = s, (f,r)
        return best_c, best_s

    start_pos = 0
    if start:
        grid[0][0] = start
        used.add(start[0])
        start_pos = 1

    total = 0.0
    for pos in range(start_pos, 16):
        r,c = pos//4, pos%4
        best, bs = best_for(r,c)
        if not best: return None, float('inf')
        grid[r][c] = best
        used.add(best[0])
        total += bs
    return grid, total

print("Running greedy...", flush=True)
best_grid, best_score = greedy_fill()
print(f"Initial score: {best_score:.3f}", flush=True)

# Try a few starting pieces
for fn in fnames[:12]:
    for rot in ROTATIONS:
        g, s = greedy_fill((fn, rot))
        if g and s < best_score:
            best_score = s
            best_grid = g
            print(f"Better: {fn} rot={rot} score={s:.3f}", flush=True)

print(f"Best score: {best_score:.3f}", flush=True)

# Compute actual total edge score
def total_score(grid):
    t, n = 0.0, 0
    for r in range(4):
        for c in range(4):
            if not grid[r][c]: continue
            f,rot = grid[r][c]
            if c<3 and grid[r][c+1]:
                f2,r2 = grid[r][c+1]
                t += h_sc[f][rot][f2][r2]; n+=1
            if r<3 and grid[r+1][c]:
                f2,r2 = grid[r+1][c]
                t += v_sc[f][rot][f2][r2]; n+=1
    return t/n if n>0 else float('inf')

final_ts = total_score(best_grid)
print(f"Final total score: {final_ts:.3f}", flush=True)

print("\nGrid layout:", flush=True)
for r in range(4):
    row_str = []
    for c in range(4):
        if best_grid[r][c]:
            f,rot = best_grid[r][c]
            row_str.append(f"{f}(r{rot})")
    print(" | ".join(row_str), flush=True)

# Assemble
print("\nAssembling...", flush=True)
result = Image.new("RGB", (600,600))
for r in range(4):
    for c in range(4):
        if best_grid[r][c]:
            f, rot = best_grid[r][c]
            arr = rotate_arr(pieces[f], rot).astype(np.uint8)
            result.paste(Image.fromarray(arr), (c*150, r*150))

result.save(OUTPUT_DIR + "assembled.png")
print("Saved assembled.png", flush=True)

# Build outputs
used_pieces = {best_grid[r][c][0] for r in range(4) for c in range(4) if best_grid[r][c]}
distractors = sorted([f for f in fnames if f not in used_pieces])
transforms = {}
for r in range(4):
    for c in range(4):
        if best_grid[r][c]:
            f,rot = best_grid[r][c]
            if rot != 0:
                transforms[f] = f"rotate_{rot}"

grid_names = [[best_grid[r][c][0] if best_grid[r][c] else None for c in range(4)] for r in range(4)]

result_data = {
    "grid": grid_names,
    "transforms": transforms,
    "distractors": distractors,
    "description": "待视觉识别"
}
with open(OUTPUT_DIR+"result.json","w",encoding="utf-8") as fp:
    json.dump(result_data, fp, ensure_ascii=False, indent=2)
print("Saved result.json", flush=True)
print("DONE", flush=True)
